  1→import { useState, useEffect, useRef, useCallback } from "react";
  2→import { invoke } from "@tauri-apps/api/core";
  3→import { Sidebar } from "./features/repos/Sidebar";
  4→import { useReposQuery } from "./hooks/use-tauri-query";
  5→import { TitleBar } from "./components/TitleBar";
  6→import { TabBar } from "./components/TabBar";
  7→import { CheckpointList } from "./features/checkpoints/CheckpointList";
  8→import { TranscriptView } from "./features/transcripts/TranscriptView";
  9→import { DiffView, BranchDiffView } from "./features/diff/DiffView";
 10→import { CheckpointInsightsContainer } from "./features/insights/CheckpointInsightsContainer";
 11→import { BranchInsightsContainer } from "./features/insights/BranchInsightsContainer";
 12→import { BranchDebugContainer } from "./features/debug/BranchDebugContainer";
 13→import { CheckpointDebugContainer } from "./features/debug/CheckpointDebugContainer";
 14→import { TerminalPanel } from "./features/terminal/TerminalPanel";
 15→import type { TerminalPanelHandle } from "./features/terminal/TerminalPanel";
 16→import { createBranchTab, createWorktreeTab } from "./features/repos/tab-state";
 17→import { DEFAULT_SIDEBAR_WIDTH, clampSidebarWidth } from "./features/repos/sidebar-width.ts";
 18→import { planWorktreeDeletionCleanup } from "./features/repos/worktree-delete-state.ts";
 19→import {
 20→  collectWorkspaceSurfaceIds,
 21→  createTerminalWorkspace,
 22→  type TerminalWorkspace,
 23→  type WorkspaceUpdate,
 24→} from "./features/terminal/workspace";
 25→import {
 26→  createTerminalPanelVisibility,
 27→  isTerminalPanelOpen,
 28→  setTerminalPanelOpen,
 29→  syncTerminalPanelVisibility,
 30→} from "./features/terminal/panel-visibility";
 31→import {
 32→  DEFAULT_TERMINAL_HEIGHT,
 33→  clampTerminalHeight,
 34→} from "./features/terminal/resize.ts";
 35→import { useLiveUpdates } from "./hooks/use-live-updates";
 36→import type { BranchInfo, CheckpointSummary, WorktreeInfo } from "./lib/ipc";
 37→import { SettingsView } from "./features/settings/SettingsView";
 38→import { ArrowLeft, GitCommit } from "lucide-react";
 39→
 40→export interface Tab {
 41→  id: string;
 42→  branch: string;
 43→  repoPath: string;
 44→  worktree: WorktreeInfo | null;
 45→  kind: "branch" | "agent";
 46→  agent: string | null;
 47→  hasActiveSession: boolean;
 48→}
 49→
 50→function resolveAgent(agent: string) {
 51→  return agent === "codex" ? "codex" : "claude-code";
 52→}
 53→
 54→export default function App() {
 55→  const [tabs, setTabs] = useState<Tab[]>([
 56→    {
 57→      id: "main",
 58→      branch: "main",
 59→      repoPath: "",
 60→      worktree: null,
 61→      kind: "branch",
 62→      agent: null,
 63→      hasActiveSession: false,
 64→    },
 65→  ]);
 66→  const [activeTabId, setActiveTabId] = useState("main");
 67→  const [sidebarWidth, setSidebarWidth] = useState(DEFAULT_SIDEBAR_WIDTH);
 68→  const [terminalHeight, setTerminalHeight] = useState(() => {
 69→    const storedHeight = Number(localStorage.getItem("entire:terminal-height"));
 70→    const initialHeight = Number.isFinite(storedHeight) && storedHeight > 0
 71→      ? storedHeight
 72→      : DEFAULT_TERMINAL_HEIGHT;
 73→
 74→    return clampTerminalHeight(initialHeight, window.innerHeight);
 75→  });
 76→  const [checkpointListWidth, setCheckpointListWidth] = useState(() => {
 77→    const stored = Number(localStorage.getItem("entire:checkpoint-list-width"));
 78→    return Number.isFinite(stored) && stored >= 200 ? Math.min(stored, 500) : 320;
 79→  });
 80→  const [terminalPanelVisibility, setTerminalPanelVisibility] = useState(
 81→    () => createTerminalPanelVisibility(["main"])
 82→  );
 83→  const [innerTab, setInnerTab] = useState<
 84→    "checkpoints" | "diff" | "insights" | "debug"
 85→  >("checkpoints");
 86→  const [selectedCheckpoint, setSelectedCheckpoint] =
 87→    useState<CheckpointSummary | null>(null);
 88→  const [checkpointInnerTab, setCheckpointInnerTab] = useState<
 89→    "transcript" | "diff" | "insights" | "debug"
 90→  >("transcript");
 91→
 92→  const [workspaceMap, setWorkspaceMap] = useState<Map<string, TerminalWorkspace>>(
 93→    () => new Map([["main", createTerminalWorkspace()]])
 94→  );
 95→  const [pendingAgentLaunch, setPendingAgentLaunch] = useState<{
 96→    tabId: string;
 97→    agent: string;
 98→    prompt: string;
 99→  } | null>(null);
100→  const [isSidebarDialogOpen, setIsSidebarDialogOpen] = useState(false);
101→  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
102→
103→  const terminalRef = useRef<TerminalPanelHandle>(null);
104→
105→  // Load repos so we can auto-populate the initial tab
106→  const { data: repos } = useReposQuery();
107→
108→  // Auto-populate the initial tab's repoPath from the first discovered repo
109→  useEffect(() => {
110→    invoke("debug_log", {
111→      message: `useEffect[repos]: repos=${repos ? repos.length : "null"}, first repo path=${repos?.[0]?.path ?? "none"}`,
112→    }).catch(() => {});
113→
114→    if (!repos || repos.length === 0) return;
115→    setTabs((prev) => {
116→      const updated = prev.map((tab) => {
117→        if (tab.id === "main" && !tab.repoPath) {
118→          const repo = repos[0];
119→          const headBranch = repo.branches.find((b: { is_head: boolean }) => b.is_head);
120→          const newPath = repo.path;
121→          const newBranch = headBranch?.name ?? repo.branches[0]?.name ?? "main";
122→          invoke("debug_log", {
123→            message: `Auto-populating initial tab: repoPath=${newPath}, branch=${newBranch}`,
124→          }).catch(() => {});
125→          return {
126→            ...tab,
127→            repoPath: newPath,
128→            branch: newBranch,
129→          };
130→        }
131→        return tab;
132→      });
133→      return updated;
134→    });
135→  }, [repos]);
136→
137→  const activeTab = tabs.find((t) => t.id === activeTabId) ?? tabs[0];
138→  const activeWorkspace =
139→    workspaceMap.get(activeTabId) ?? createTerminalWorkspace();
140→  const isTerminalOpen = isTerminalPanelOpen(terminalPanelVisibility, activeTabId);
141→  const tabsWithSessions = tabs.map((tab) => ({
142→    ...tab,
143→    hasActiveSession: collectWorkspaceSurfaceIds(workspaceMap.get(tab.id)).length > 0,
144→  }));
145→
146→  // Live updates — watch active repo for checkpoint/session changes
147→  useLiveUpdates(activeTab.repoPath);
148→
149→  useEffect(() => {
150→    setWorkspaceMap((prev) => {
151→      let changed = false;
152→      const next = new Map(prev);
153→      for (const tab of tabs) {
154→        if (!next.has(tab.id)) {
155→          next.set(tab.id, createTerminalWorkspace());
156→          changed = true;
157→        }
158→      }
159→      return changed ? next : prev;
160→    });
161→  }, [tabs]);
162→
163→  useEffect(() => {
164→    setTerminalPanelVisibility((prev) =>
165→      syncTerminalPanelVisibility(
166→        prev,
167→        tabs.map((tab) => tab.id)
168→      )
169→    );
170→  }, [tabs]);
171→
172→  const handleWorkspaceChange = useCallback(
173→    (tabId: string, update: WorkspaceUpdate) => {
174→      setWorkspaceMap((prev) => {
175→        const next = new Map(prev);
176→        const current = next.get(tabId) ?? createTerminalWorkspace();
177→        next.set(
178→          tabId,
179→          typeof update === "function" ? update(current) : update
180→        );
181→        return next;
182→      });
183→    },
184→    []
185→  );
186→
187→  const handleSetTerminalOpen = useCallback((tabId: string, isOpen: boolean) => {
188→    setTerminalPanelVisibility((prev) => setTerminalPanelOpen(prev, tabId, isOpen));
189→  }, []);
190→
191→  // Terminal dispatch — open shell and optionally send a prompt
192→  const handleSendToAgent = useCallback(
193→    (agent: string, prompt: string) => {
194→      if (!activeTab.repoPath) return;
195→
196→      const resolvedAgent = resolveAgent(agent);
197→      const tabId = `agent:${resolvedAgent}:${Date.now()}`;
198→      const agentTab: Tab = {
199→        id: tabId,
200→        branch: activeTab.branch,
201→        repoPath: activeTab.repoPath,
202→        worktree: activeTab.worktree,
203→        kind: "agent",
204→        agent: resolvedAgent,
205→        hasActiveSession: false,
206→      };
207→
208→      setTabs((prev) => [...prev, agentTab]);
209→      setActiveTabId(tabId);
210→      handleSetTerminalOpen(tabId, true);
211→      setPendingAgentLaunch({ tabId, agent: resolvedAgent, prompt });
212→    },
213→    [activeTab, handleSetTerminalOpen]
214→  );
215→
216→  useEffect(() => {
217→    if (!pendingAgentLaunch) return;
218→    if (pendingAgentLaunch.tabId !== activeTabId) return;
219→    if (!isTerminalOpen) return;
220→
221→    let cancelled = false;
222→    let timer = 0;
223→
224→    const launch = () => {
225→      if (cancelled) return;
226→      if (!terminalRef.current) {
227→        timer = window.setTimeout(launch, 50);
228→        return;
229→      }
230→
231→      terminalRef.current
232→        .launchSession({
233→          agent: pendingAgentLaunch.agent,
234→          prompt: pendingAgentLaunch.prompt,
235→        })
236→        .finally(() => {
237→          setPendingAgentLaunch((current) =>
238→            current?.tabId === pendingAgentLaunch.tabId ? null : current
239→          );
240→        });
241→    };
242→
243→    timer = window.setTimeout(launch, 50);
244→    return () => {
245→      cancelled = true;
246→      window.clearTimeout(timer);
247→    };
248→  }, [activeTabId, isTerminalOpen, pendingAgentLaunch]);
249→
250→  // Persist UI state to localStorage
251→  useEffect(() => {
252→    localStorage.setItem("entire:terminal-height", String(terminalHeight));
253→  }, [terminalHeight]);
254→  useEffect(() => {
255→    localStorage.setItem("entire:checkpoint-list-width", String(checkpointListWidth));
256→  }, [checkpointListWidth]);
257→  useEffect(() => {
258→    function handleWindowResize() {
259→      setTerminalHeight((currentHeight) =>
260→        clampTerminalHeight(currentHeight, window.innerHeight)
261→      );
262→    }
263→
264→    window.addEventListener("resize", handleWindowResize);
265→    return () => window.removeEventListener("resize", handleWindowResize);
266→  }, []);
267→
268→  // Clear selected checkpoint when switching branch tabs
269→  useEffect(() => {
270→    setSelectedCheckpoint(null);
271→    setCheckpointInnerTab("transcript");
272→  }, [activeTabId]);
273→
274→  // Keyboard shortcuts
275→  useEffect(() => {
276→    function onKeyDown(e: KeyboardEvent) {
277→      const meta = e.metaKey || e.ctrlKey;
278→
279→      // Cmd+K = focus search
280→      if (meta && e.key === "k") {
281→        e.preventDefault();
282→        document.querySelector<HTMLInputElement>('input[placeholder*="Search"]')?.focus();
283→      }
284→      // Ctrl+` = toggle terminal
285→      if (e.ctrlKey && e.key === "`") {
286→        e.preventDefault();
287→        handleSetTerminalOpen(activeTabId, !isTerminalOpen);
288→      }
289→      // Cmd+W = close active tab
290→      if (meta && e.key === "w") {
291→        e.preventDefault();
292→        handleCloseTab(activeTabId);
293→      }
294→      // Cmd+1-9 = switch to tab by index
295→      if (meta && e.key >= "1" && e.key <= "9") {
296→        e.preventDefault();
297→        const idx = parseInt(e.key) - 1;
298→        if (idx < tabs.length) {
299→          setActiveTabId(tabs[idx].id);
300→        }
301→      }
302→      // Cmd+[ / Cmd+] = prev/next tab
303→      if (meta && e.key === "[") {
304→        e.preventDefault();
305→        const idx = tabs.findIndex((t) => t.id === activeTabId);
306→        if (idx > 0) setActiveTabId(tabs[idx - 1].id);
307→      }
308→      if (meta && e.key === "]") {
309→        e.preventDefault();
310→        const idx = tabs.findIndex((t) => t.id === activeTabId);
311→        if (idx < tabs.length - 1) setActiveTabId(tabs[idx + 1].id);
312→      }
313→      // Escape = deselect checkpoint
314→      if (e.key === "Escape" && selectedCheckpoint) {
315→        setSelectedCheckpoint(null);
316→      }
317→    }
318→    window.addEventListener("keydown", onKeyDown);
319→    return () => window.removeEventListener("keydown", onKeyDown);
320→  }, [activeTabId, handleSetTerminalOpen, isTerminalOpen, tabs, selectedCheckpoint]);
321→
322→  function handleBranchSelect(branch: BranchInfo, repoPath: string) {
323→    const newTab = createBranchTab(branch, repoPath);
324→    const existing = tabs.find(
325→      (t) =>
326→        t.kind === "branch" &&
327→        t.branch === newTab.branch &&
328→        t.repoPath === newTab.repoPath
329→    );
330→    if (existing) {
331→      setActiveTabId(existing.id);
332→    } else {
333→      setTabs([...tabs, newTab]);
334→      setActiveTabId(newTab.id);
335→    }
336→  }
337→
338→  function handleWorktreeSelect(wt: WorktreeInfo) {
339→    const newTab = createWorktreeTab(wt);
340→    const existing = tabs.find(
341→      (t) =>
342→        t.kind === "branch" &&
343→        t.branch === newTab.branch &&
344→        t.repoPath === newTab.repoPath
345→    );
346→    if (existing) {
347→      setActiveTabId(existing.id);
348→    } else {
349→      setTabs([...tabs, newTab]);
350→      setActiveTabId(newTab.id);
351→    }
352→  }
353→
354→  function handleCloseTab(tabId: string) {
355→    if (tabs.length <= 1) return;
356→    const idx = tabs.findIndex((t) => t.id === tabId);
357→    const newTabs = tabs.filter((t) => t.id !== tabId);
358→    setTabs(newTabs);
359→    if (activeTabId === tabId) {
360→      setActiveTabId(newTabs[Math.max(0, idx - 1)].id);
361→    }
362→    const closedWorkspace = workspaceMap.get(tabId);
363→    for (const surfaceId of collectWorkspaceSurfaceIds(closedWorkspace)) {
364→      invoke("ghostty_destroy_surface", { surfaceId }).catch(console.error);
365→    }
366→    setWorkspaceMap((prev) => {
367→      const next = new Map(prev);
368→      next.delete(tabId);
369→      return next;
370→    });
371→  }
372→
373→  function handleBranchDeleted(branchName: string, repoPath: string) {
374→    const tabsToRemove = tabs.filter(
375→      (tab) =>
376→        tab.kind === "branch" &&
377→        tab.worktree === null &&
378→        tab.branch === branchName &&
379→        tab.repoPath === repoPath
380→    );
381→
382→    if (tabsToRemove.length === 0) {
383→      return;
384→    }
385→
386→    const nextTabs = tabs.filter((tab) => !tabsToRemove.some((candidate) => candidate.id === tab.id));
387→    setTabs(nextTabs);
388→
389→    if (tabsToRemove.some((tab) => tab.id === activeTabId) && nextTabs.length > 0) {
390→      setActiveTabId(nextTabs[0].id);
391→    }
392→
393→    setWorkspaceMap((prev) => {
394→      const next = new Map(prev);
395→      for (const tab of tabsToRemove) {
396→        const closedWorkspace = next.get(tab.id);
397→        for (const surfaceId of collectWorkspaceSurfaceIds(closedWorkspace)) {
398→          invoke("ghostty_destroy_surface", { surfaceId }).catch(console.error);
399→        }
400→        next.delete(tab.id);
401→      }
402→      return next;
403→    });
404→  }
405→
406→  function handleWorktreeDeleted(worktreePath: string) {
407→    const cleanup = planWorktreeDeletionCleanup({
408→      tabs,
409→      activeTabId,
410→      worktreePath,
411→    });
412→
413→    if (cleanup.removedTabIds.length === 0) {
414→      return;
415→    }
416→
417→    setTabs(cleanup.remainingTabs);
418→
419→    if (cleanup.nextActiveTabId && cleanup.nextActiveTabId !== activeTabId) {
420→      setActiveTabId(cleanup.nextActiveTabId);
421→    }
422→
423→    setWorkspaceMap((prev) => {
424→      const next = new Map(prev);
425→      for (const tabId of cleanup.removedTabIds) {
426→        const closedWorkspace = next.get(tabId);
427→        for (const surfaceId of collectWorkspaceSurfaceIds(closedWorkspace)) {
428→          invoke("ghostty_destroy_surface", { surfaceId }).catch(console.error);
429→        }
430→        next.delete(tabId);
431→      }
432→      return next;
433→    });
434→  }
435→
436→  function handleResizeStart(e: React.MouseEvent) {
437→    e.preventDefault();
438→    const startY = e.clientY;
439→    const startHeight = terminalHeight;
440→
441→    function onMouseMove(ev: MouseEvent) {
442→      const delta = startY - ev.clientY;
443→      setTerminalHeight(
444→        clampTerminalHeight(startHeight + delta, window.innerHeight)
445→      );
446→    }
447→    function onMouseUp() {
448→      window.removeEventListener("mousemove", onMouseMove);
449→      window.removeEventListener("mouseup", onMouseUp);
450→    }
451→    window.addEventListener("mousemove", onMouseMove);
452→    window.addEventListener("mouseup", onMouseUp);
453→  }
454→
455→  function handleSidebarResizeStart(e: React.MouseEvent<HTMLDivElement>) {
456→    e.preventDefault();
457→    const startX = e.clientX;
458→    const startWidth = sidebarWidth;
459→
460→    function onMouseMove(ev: MouseEvent) {
461→      const delta = ev.clientX - startX;
462→      setSidebarWidth(clampSidebarWidth(startWidth + delta));
463→    }
464→
465→    function onMouseUp() {
466→      window.removeEventListener("mousemove", onMouseMove);
467→      window.removeEventListener("mouseup", onMouseUp);
468→    }
469→
470→    window.addEventListener("mousemove", onMouseMove);
471→    window.addEventListener("mouseup", onMouseUp);
472→  }
473→
474→  function handleCheckpointListResizeStart(e: React.MouseEvent<HTMLDivElement>) {
475→    e.preventDefault();
476→    const startX = e.clientX;
477→    const startWidth = checkpointListWidth;
478→
479→    function onMouseMove(ev: MouseEvent) {
480→      const delta = ev.clientX - startX;
481→      setCheckpointListWidth(Math.max(200, Math.min(500, startWidth + delta)));
482→    }
483→
484→    function onMouseUp() {
485→      window.removeEventListener("mousemove", onMouseMove);
486→      window.removeEventListener("mouseup", onMouseUp);
487→    }
488→
489→    window.addEventListener("mousemove", onMouseMove);
490→    window.addEventListener("mouseup", onMouseUp);
491→  }
492→
493→  const repoName = activeTab.repoPath
494→    ? activeTab.repoPath.split("/").pop()
495→    : "";
496→
497→  return (
498→    <div className="flex h-screen flex-col">
499→      <TitleBar
500→        title={`Entire — ${repoName ? `${repoName}/` : ""}${activeTab?.branch ?? ""}`}
501→      />
502→
503→      <div className="flex flex-1 overflow-hidden">
504→        {/* Sidebar */}
505→        <Sidebar
506→          activeTab={activeTab}
507→          width={sidebarWidth}
508→          onBranchSelect={handleBranchSelect}
509→          onBranchDeleted={handleBranchDeleted}
510→          onWorktreeDeleted={handleWorktreeDeleted}
511→          onWorktreeSelect={handleWorktreeSelect}
512→          onResizeStart={handleSidebarResizeStart}
513→          onDialogOpen={setIsSidebarDialogOpen}
514→          onOpenSettings={() => setIsSettingsOpen(true)}
515→        />
516→
517→        {/* Main content */}
518→        <div className="flex flex-1 flex-col overflow-hidden">
519→          <TabBar
520→            tabs={tabsWithSessions}
521→            activeTabId={activeTabId}
522→            onSelectTab={setActiveTabId}
523→            onCloseTab={handleCloseTab}
524→          />
525→
526→          <div className="flex flex-1 flex-col overflow-hidden">
527→            {/* Inner tabs */}
528→            <div className="flex gap-0 border-b border-border-subtle bg-bg px-5 pt-3">
529→              {(["checkpoints", "diff", "insights", "debug"] as const).map((tab) => (
530→                <button
531→                  key={tab}
532→                  onClick={() => setInnerTab(tab)}
533→                  className={`border-b-2 px-4 pb-2 text-xs font-medium capitalize transition-colors ${
534→                    innerTab === tab
535→                      ? "border-accent text-fg"
536→                      : "border-transparent text-fg-subtle hover:text-fg-muted"
537→                  }`}
538→                >
539→                  {tab === "checkpoints"
540→                    ? "Checkpoints"
541→                    : tab === "diff"
542→                      ? "Diff"
543→                      : tab === "insights"
544→                        ? "Insights"
545→                        : "Debug"}
546→                </button>
547→              ))}
548→            </div>
549→
550→            {/* Main view */}
551→            <div className="flex flex-1 overflow-hidden bg-bg">
552→              {innerTab === "checkpoints" && (
553→                <>
554→                  {/* Checkpoint list — always visible when on checkpoints tab */}
555→                  <div
556→                    className={`overflow-y-auto ${
557→                      selectedCheckpoint
558→                        ? "shrink-0 border-r border-border-subtle"
559→                        : "flex-1"
560→                    }`}
561→                    style={selectedCheckpoint ? { width: checkpointListWidth } : undefined}
562→                  >
563→                    <CheckpointList
564→                      repoPath={activeTab.repoPath}
565→                      branch={activeTab.branch}
566→                      onSelectCheckpoint={(cp) => {
567→                        setSelectedCheckpoint(cp);
568→                        setCheckpointInnerTab("transcript");
569→                      }}
570→                    />
571→                  </div>
572→
573→                  {/* Checkpoint list resize handle */}
574→                  {selectedCheckpoint && (
575→                    <div
576→                      onMouseDown={handleCheckpointListResizeStart}
577→                      className="w-[3px] shrink-0 cursor-col-resize bg-border transition-colors hover:bg-accent"
578→                    />
579→                  )}
580→
581→                  {/* Checkpoint detail panel */}
582→                  {selectedCheckpoint && (
583→                    <div className="flex flex-1 flex-col overflow-hidden">
584→                      {/* Detail header */}
585→                      <div className="flex items-center gap-3 border-b border-border-subtle px-4 py-2.5">
586→                        <button
587→                          onClick={() => setSelectedCheckpoint(null)}
588→                          className="flex items-center gap-1.5 text-xs text-fg-subtle transition-colors hover:text-fg"
589→                        >
590→                          <ArrowLeft size={14} />
591→                        </button>
592→                        <GitCommit size={14} className="text-fg-subtle" />
593→                        <span className="font-mono text-xs text-accent-fg">
594→                          {selectedCheckpoint.commit_sha
595→                            ? selectedCheckpoint.commit_sha.slice(0, 7)
596→                            : selectedCheckpoint.checkpoint_id.slice(0, 7)}
597→                        </span>
598→                        <span className="truncate text-xs text-fg-muted">
599→                          {selectedCheckpoint.commit_message || "Untitled"}
600→                        </span>
601→                      </div>
602→
603→                      {/* Checkpoint sub-tabs */}
604→                      <div className="flex gap-0 border-b border-border-subtle bg-bg px-4 pt-2">
605→                        {(["transcript", "diff", "insights", "debug"] as const).map(
606→                          (tab) => (
607→                            <button
608→                              key={tab}
609→                              onClick={() => setCheckpointInnerTab(tab)}
610→                              className={`border-b-2 px-3 pb-1.5 text-[11px] font-medium capitalize transition-colors ${
611→                                checkpointInnerTab === tab
612→                                  ? "border-accent text-fg"
613→                                  : "border-transparent text-fg-subtle hover:text-fg-muted"
614→                              }`}
615→                            >
616→                              {tab === "transcript"
617→                                ? "Transcript"
618→                                : tab === "diff"
619→                                  ? "Diff"
620→                                  : tab === "insights"
621→                                    ? "Insights"
622→                                    : "Debug"}
623→                            </button>
624→                          )
625→                        )}
626→                      </div>
627→
628→                      {/* Checkpoint detail content */}
