 86→fn truncate_for_budget(content: &str, max_chars: usize) -> String {
 87→    let chars: Vec<char> = content.chars().collect();
 88→    if chars.len() <= max_chars {
 89→        return content.to_string();
 90→    }
 91→
 92→    chars[..max_chars].iter().collect()
 93→}
