117→#[tauri::command]
118→fn get_transcript(
119→    repo_path: String,
120→    checkpoint_id: String,
121→    session_index: u32,
122→) -> Result<Vec<session::TranscriptMessage>, String> {
123→    let repo = git::open_repo(&repo_path)?;
124→
125→    let prefix = &checkpoint_id[..2];
126→    let suffix = &checkpoint_id[2..];
127→    let meta_path = format!("{}/{}/metadata.json", prefix, suffix);
128→    let meta_content = read_blob(&repo, &meta_path).ok();
129→    let candidates =
130→        transcript_candidate_paths(&checkpoint_id, session_index, meta_content.as_deref());
131→
132→    for path in &candidates {
133→        if let Ok(content) = read_blob(&repo, path) {
134→            return Ok(session::read_transcript(&content));
135→        }
136→    }
137→
138→    Err(format!("Transcript not found for checkpoint {} session {}", checkpoint_id, session_index))
139→}
