184→/// Read a blob from the entire/checkpoints/v1 branch by path
185→fn read_blob(repo: &git2::Repository, path: &str) -> Result<String, String> {
186→    let branch_ref = repo
187→        .find_branch("entire/checkpoints/v1", git2::BranchType::Local)
188→        .map_err(|e| format!("No checkpoint branch: {}", e))?;
189→
190→    let commit = branch_ref
191→        .get()
192→        .peel_to_commit()
193→        .map_err(|e| format!("Failed to peel: {}", e))?;
194→
195→    let tree = commit
196→        .tree()
197→        .map_err(|e| format!("Failed to get tree: {}", e))?;
198→
199→    let entry = tree
200→        .get_path(std::path::Path::new(path))
201→        .map_err(|e| format!("Path not found: {}", e))?;
202→
203→    let blob = repo
204→        .find_blob(entry.id())
205→        .map_err(|e| format!("Failed to read blob: {}", e))?;
206→
207→    std::str::from_utf8(blob.content())
208→        .map(|s| s.to_string())
209→        .map_err(|e| format!("Invalid UTF-8: {}", e))
210→}
