17→    (trimmed.startsWith("[") && trimmed.endsWith("]"))
18→  ) {
19→    try {
20→      JSON.parse(trimmed);
21→      return true;
22→    } catch {
23→      return false;
24→    }
25→  }
26→  return false;
27→}
