423→/// Convert a git2::Diff into our FileDiff structs
424→fn collect_diff_files(diff: &git2::Diff) -> Result<Vec<FileDiff>, String> {
425→    let mut files: Vec<FileDiff> = Vec::new();
426→
427→    diff.print(git2::DiffFormat::Patch, |delta, hunk, line| {
428→        let path = delta
429→            .new_file()
430→            .path()
431→            .or_else(|| delta.old_file().path())
432→            .map(|p| p.to_string_lossy().to_string())
433→            .unwrap_or_default();
434→
435→        let status = match delta.status() {
436→            git2::Delta::Added => "added",
437→            git2::Delta::Deleted => "deleted",
438→            _ => "modified",
439→        };
440→
441→        // Ensure we have a FileDiff entry for this path
442→        if files.last().map_or(true, |f| f.path != path) {
443→            files.push(FileDiff {
444→                path: path.clone(),
445→                status: status.to_string(),
446→                hunks: Vec::new(),
447→            });
448→        }
449→
450→        let file = files.last_mut().unwrap();
451→
452→        // New hunk
453→        if let Some(h) = hunk {
454→            let header = std::str::from_utf8(h.header()).unwrap_or("").to_string();
455→            if file.hunks.last().map_or(true, |last| last.header != header) {
456→                file.hunks.push(DiffHunk {
457→                    header,
458→                    lines: Vec::new(),
459→                });
460→            }
461→        }
462→
463→        // Diff line
464→        if let Some(current_hunk) = file.hunks.last_mut() {
465→            let kind = match line.origin() {
466→                '+' => "add",
467→                '-' => "delete",
468→                ' ' => "context",
469→                _ => return true,
470→            };
471→            let content = std::str::from_utf8(line.content()).unwrap_or("").to_string();
472→            current_hunk.lines.push(DiffLine {
473→                kind: kind.to_string(),
474→                content,
475→                old_lineno: line.old_lineno(),
476→                new_lineno: line.new_lineno(),
477→            });
478→        }
479→
480→        true
481→    })
482→    .map_err(|e| format!("Failed to print diff: {}", e))?;
483→
484→    Ok(files)
485→}
