487→fn collect_checkpoint_diff(
488→    repo: &git2::Repository,
489→    commit_sha: &str,
490→) -> Result<Vec<FileDiff>, String> {
491→    let oid = git2::Oid::from_str(commit_sha)
492→        .map_err(|e| format!("Invalid commit SHA: {}", e))?;
493→    let commit = repo
494→        .find_commit(oid)
495→        .map_err(|e| format!("Commit not found: {}", e))?;
496→
497→    let tree = commit
498→        .tree()
499→        .map_err(|e| format!("Failed to get tree: {}", e))?;
500→
501→    let parent_tree = commit.parent(0).ok().and_then(|p| p.tree().ok());
502→
503→    let diff = repo
504→        .diff_tree_to_tree(parent_tree.as_ref(), Some(&tree), None)
505→        .map_err(|e| format!("Failed to compute diff: {}", e))?;
506→
507→    collect_diff_files(&diff)
508→}
