510→fn load_sanitized_checkpoint_transcripts(
511→    repo: &git2::Repository,
512→    checkpoint_id: &str,
513→) -> Result<Vec<semantic_review::PromptTranscriptSession>, String> {
514→    let prefix = &checkpoint_id[..2];
515→    let suffix = &checkpoint_id[2..];
516→    let meta_path = format!("{}/{}/metadata.json", prefix, suffix);
517→    let meta_content = read_blob(repo, &meta_path)?;
518→    let meta = serde_json::from_str::<CheckpointReviewMetadata>(&meta_content)
519→        .map_err(|e| format!("Failed to parse checkpoint metadata: {}", e))?;
520→
521→    let session_count = meta.sessions.map(|sessions| sessions.len()).unwrap_or(0);
522→    let mut all_sessions = Vec::new();
523→
524→    for session_index in 0..session_count {
525→        let candidates =
526→            transcript_candidate_paths(checkpoint_id, session_index as u32, Some(&meta_content));
527→        let mut transcript_content = None;
528→        for path in candidates {
529→            if let Ok(content) = read_blob(repo, &path) {
530→                transcript_content = Some(content);
531→                break;
532→            }
533→        }
534→
535→        let Some(content) = transcript_content else {
536→            continue;
537→        };
538→
539→        let parsed = session::read_transcript(&content);
540→        let sanitized = session::sanitize_transcript_for_semantic_review(&parsed, 4_000);
541→        if sanitized.is_empty() {
542→            continue;
543→        }
544→
545→        all_sessions.push(semantic_review::PromptTranscriptSession {
546→            session_index: session_index as u32,
547→            messages: sanitized
548→                .into_iter()
549→                .map(|message| semantic_review::PromptTranscriptMessage {
550→                    role: message.role,
551→                    content: message.content,
552→                })
553→                .collect(),
554→        });
555→    }
556→
557→    Ok(all_sessions)
558→}
