667→#[tauri::command]
668→fn get_branch_diff(
669→    repo_path: String,
670→    branch: String,
671→) -> Result<Vec<FileDiff>, String> {
672→    let repo = git::open_repo(&repo_path)?;
673→
674→    // Resolve the branch HEAD
675→    let branch_ref = repo
676→        .find_branch(&branch, git2::BranchType::Local)
677→        .map_err(|e| format!("Branch not found: {}", e))?;
678→    let branch_commit = branch_ref
679→        .get()
680→        .peel_to_commit()
681→        .map_err(|e| format!("Failed to resolve branch HEAD: {}", e))?;
682→
683→    // Find the default branch (try main, then master)
684→    let default_branch_name = if repo.find_branch("main", git2::BranchType::Local).is_ok() {
685→        "main"
686→    } else if repo.find_branch("master", git2::BranchType::Local).is_ok() {
687→        "master"
688→    } else {
689→        return Err("No default branch (main/master) found".to_string());
690→    };
691→
692→    // If we're diffing the default branch against itself, return empty
693→    if branch == default_branch_name {
694→        return Ok(Vec::new());
695→    }
696→
697→    let default_ref = repo
698→        .find_branch(default_branch_name, git2::BranchType::Local)
699→        .map_err(|e| format!("Default branch error: {}", e))?;
700→    let default_commit = default_ref
701→        .get()
702→        .peel_to_commit()
703→        .map_err(|e| format!("Failed to resolve default branch: {}", e))?;
704→
705→    // Find merge base
706→    let merge_base_oid = repo
707→        .merge_base(default_commit.id(), branch_commit.id())
708→        .map_err(|e| format!("Failed to find merge base: {}", e))?;
709→    let merge_base_commit = repo
710→        .find_commit(merge_base_oid)
711→        .map_err(|e| format!("Failed to find merge base commit: {}", e))?;
712→
713→    let base_tree = merge_base_commit
714→        .tree()
715→        .map_err(|e| format!("Failed to get base tree: {}", e))?;
716→    let branch_tree = branch_commit
717→        .tree()
718→        .map_err(|e| format!("Failed to get branch tree: {}", e))?;
719→
720→    let diff = repo
721→        .diff_tree_to_tree(Some(&base_tree), Some(&branch_tree), None)
722→        .map_err(|e| format!("Failed to compute branch diff: {}", e))?;
723→
724→    collect_diff_files(&diff)
725→}
