727→#[tauri::command]
728→fn watch_repo(
729→    repo_path: String,
730→    app: tauri::AppHandle,
731→    state: State<'_, Mutex<AppState>>,
732→) -> Result<(), String> {
733→    let mut app_state = state.lock().map_err(|_| "State lock error".to_string())?;
734→
735→    // Don't double-watch
736→    if app_state.watched_repos.contains(&repo_path) {
737→        return Ok(());
738→    }
739→    app_state.watched_repos.insert(repo_path.clone());
740→
741→    let app_handle = app.clone();
742→    let repo_path_for_closure = repo_path.clone();
743→    watcher::watch_repo(&repo_path, move |event| {
744→        let event_name = match event {
745→            watcher::WatchEvent::CheckpointChanged => "checkpoint-changed",
746→            watcher::WatchEvent::SessionChanged(_) => "session-changed",
747→            watcher::WatchEvent::ConfigChanged => "config-changed",
748→        };
749→        let _ = app_handle.emit(event_name, serde_json::json!({
750→            "repoPath": repo_path_for_closure,
751→        }));
752→    })?;
753→
754→    Ok(())
755→}
