 14→/// Read .entire/settings.json from a repo
 15→pub fn read_settings(repo_path: &str) -> Result<EntireSettings, String> {
 16→    let settings_path = Path::new(repo_path).join(".entire/settings.json");
 17→    if !settings_path.exists() {
 18→        return Err("No .entire/settings.json found".to_string());
 19→    }
 20→
 21→    let content =
 22→        fs::read_to_string(&settings_path).map_err(|e| format!("Failed to read settings: {}", e))?;
 23→
 24→    serde_json::from_str(&content).map_err(|e| format!("Failed to parse settings: {}", e))
 25→}
