105→pub fn get_repo_info(path: &str) -> Result<RepoInfo, String> {
106→    let repo = open_repo(path)?;
107→    let name = Path::new(path)
108→        .file_name()
109→        .map(|n| n.to_string_lossy().to_string())
110→        .unwrap_or_else(|| "unknown".to_string());
111→
112→    let mut branches = list_branches(&repo)?;
113→    let worktrees = list_worktrees(&repo)?;
114→
115→    // Count checkpoints per branch from the checkpoint tree
116→    let counts = count_checkpoints_per_branch(&repo);
117→    for branch in &mut branches {
118→        if let Some(&count) = counts.get(&branch.name) {
119→            branch.checkpoint_count = count;
120→        }
121→    }
122→
123→    Ok(RepoInfo {
124→        path: path.to_string(),
125→        name,
126→        branches,
127→        worktrees,
128→        registered: false,
129→    })
130→}
