214→pub fn delete_worktree(
215→    repo_path: &str,
216→    worktree_path: &str,
217→    branch_name: &str,
218→    force: bool,
219→) -> Result<(), String> {
220→    if branch_name.trim().is_empty() {
221→        return Err("Branch name is required".to_string());
222→    }
223→    if worktree_path.trim().is_empty() {
224→        return Err("Worktree path is required".to_string());
225→    }
226→    if paths_match(repo_path, worktree_path) {
227→        return Err("Cannot delete the main repository checkout".to_string());
228→    }
229→
230→    open_repo(repo_path)?;
231→
232→    let remove_args = build_git_worktree_remove_args(worktree_path.trim(), force);
233→    run_git_command(repo_path, &remove_args)?;
234→
235→    let delete_args = build_git_branch_delete_args(branch_name.trim(), force);
236→    run_git_command(repo_path, &delete_args)
237→}
