354→  function handleCloseTab(tabId: string) {
355→    if (tabs.length <= 1) return;
356→    const idx = tabs.findIndex((t) => t.id === tabId);
357→    const newTabs = tabs.filter((t) => t.id !== tabId);
358→    setTabs(newTabs);
359→    if (activeTabId === tabId) {
360→      setActiveTabId(newTabs[Math.max(0, idx - 1)].id);
361→    }
362→    const closedWorkspace = workspaceMap.get(tabId);
363→    for (const surfaceId of collectWorkspaceSurfaceIds(closedWorkspace)) {
364→      invoke("ghostty_destroy_surface", { surfaceId }).catch(console.error);
365→    }
366→    setWorkspaceMap((prev) => {
367→      const next = new Map(prev);
368→      next.delete(tabId);
369→      return next;
370→    });
371→  }
