406→  function handleWorktreeDeleted(worktreePath: string) {
407→    const cleanup = planWorktreeDeletionCleanup({
408→      tabs,
409→      activeTabId,
410→      worktreePath,
411→    });
412→
413→    if (cleanup.removedTabIds.length === 0) {
414→      return;
415→    }
416→
417→    setTabs(cleanup.remainingTabs);
418→
419→    if (cleanup.nextActiveTabId && cleanup.nextActiveTabId !== activeTabId) {
420→      setActiveTabId(cleanup.nextActiveTabId);
421→    }
422→
423→    setWorkspaceMap((prev) => {
424→      const next = new Map(prev);
425→      for (const tabId of cleanup.removedTabIds) {
426→        const closedWorkspace = next.get(tabId);
427→        for (const surfaceId of collectWorkspaceSurfaceIds(closedWorkspace)) {
428→          invoke("ghostty_destroy_surface", { surfaceId }).catch(console.error);
429→        }
430→        next.delete(tabId);
431→      }
432→      return next;
433→    });
434→  }
