141→fn transcript_candidate_paths(
142→    checkpoint_id: &str,
143→    session_index: u32,
144→    meta_content: Option<&str>,
145→) -> Vec<String> {
146→    let prefix = &checkpoint_id[..2];
147→    let suffix = &checkpoint_id[2..];
148→    let requested_session_dir = format!("{}/{}/{}", prefix, suffix, session_index);
149→    let mut candidates = Vec::new();
150→
151→    let mut push_candidate = |path: String| {
152→        if !path.is_empty() && !candidates.contains(&path) {
153→            candidates.push(path);
154→        }
155→    };
156→
157→    if let Some(meta_content) = meta_content {
158→        if let Ok(meta) = serde_json::from_str::<serde_json::Value>(meta_content) {
159→            if let Some(sessions) = meta.get("sessions").and_then(|s| s.as_array()) {
160→                let mut ordered_sessions = Vec::new();
161→                if let Some(session) = sessions.get(session_index as usize) {
162→                    ordered_sessions.push(session);
163→                }
164→                for (idx, session) in sessions.iter().enumerate() {
165→                    if idx != session_index as usize {
166→                        ordered_sessions.push(session);
167→                    }
168→                }
169→
170→                for session in ordered_sessions {
171→                    if let Some(path) = session.get("transcript").and_then(|p| p.as_str()) {
172→                        push_candidate(path.trim_start_matches('/').to_string());
173→                    }
174→                }
175→            }
176→        }
177→    }
178→
179→    push_candidate(format!("{}/full.jsonl", requested_session_dir));
180→    push_candidate(format!("{}/transcript.jsonl", requested_session_dir));
181→    candidates
182→}
