281→#[tauri::command]
282→fn get_checkpoint_logs(
283→    repo_path: String,
284→    checkpoint_id: String,
285→    session_ids: Vec<String>,
286→) -> Result<EntireLogResult, String> {
287→    let log_path = std::path::Path::new(&repo_path).join(".entire/logs/entire.log");
288→    if !log_path.exists() {
289→        return Ok(EntireLogResult {
290→            lines: Vec::new(),
291→            total_lines: 0,
292→            file_size_bytes: 0,
293→        });
294→    }
295→
296→    let metadata = std::fs::metadata(&log_path)
297→        .map_err(|e| format!("Failed to read log metadata: {}", e))?;
298→    let file_size_bytes = metadata.len();
299→
300→    let file = std::fs::File::open(&log_path)
301→        .map_err(|e| format!("Failed to open log file: {}", e))?;
302→
303→    let reader = BufReader::new(file);
304→    let mut matching_lines = Vec::new();
305→
306→    for line in reader.lines() {
307→        let line = match line {
308→            Ok(l) => l,
309→            Err(_) => continue,
310→        };
311→
312→        // Parse each line as JSON and check for matching session_id or checkpoint_id
313→        if let Ok(value) = serde_json::from_str::<serde_json::Value>(&line) {
314→            let line_session_id = value.get("session_id").and_then(|v| v.as_str());
315→            let line_checkpoint_id = value.get("checkpoint_id").and_then(|v| v.as_str());
316→
317→            let matches = line_session_id
318→                .map(|sid| session_ids.iter().any(|s| s == sid))
319→                .unwrap_or(false)
320→                || line_checkpoint_id
321→                    .map(|cid| cid == checkpoint_id)
322→                    .unwrap_or(false);
323→
324→            if matches {
325→                matching_lines.push(line);
326→            }
327→        }
328→    }
329→
330→    Ok(EntireLogResult {
331→        total_lines: matching_lines.len() as u32,
332→        lines: matching_lines,
333→        file_size_bytes,
334→    })
335→}
