560→fn call_anthropic_semantic_review(prompt: &str) -> Result<String, String> {
561→    let api_key = config::read_app_settings()
562→        .anthropic_api_key
563→        .filter(|k| !k.is_empty())
564→        .or_else(|| std::env::var("ANTHROPIC_API_KEY").ok())
565→        .ok_or_else(|| "Anthropic API key is not configured. Set it in Settings or as ANTHROPIC_API_KEY env var.".to_string())?;
566→    let model = std::env::var("ANTHROPIC_MODEL")
567→        .unwrap_or_else(|_| "claude-sonnet-4-20250514".to_string());
568→
569→    let client = reqwest::blocking::Client::builder()
570→        .timeout(std::time::Duration::from_secs(90))
571→        .build()
572→        .map_err(|e| format!("Failed to build Anthropic client: {}", e))?;
573→
574→    let response = client
575→        .post("https://api.anthropic.com/v1/messages")
576→        .header("x-api-key", api_key)
577→        .header("anthropic-version", "2023-06-01")
578→        .header("content-type", "application/json")
579→        .json(&AnthropicRequest {
580→            model,
581→            max_tokens: 2_000,
582→            temperature: 0.2,
583→            system: "You are reviewing a git diff. Return JSON only with precise, line-linked explanations of the most important changes.".to_string(),
584→            messages: vec![AnthropicMessage {
585→                role: "user".to_string(),
586→                content: prompt.to_string(),
587→            }],
588→        })
589→        .send()
590→        .map_err(|e| format!("Anthropic request failed: {}", e))?
591→        .error_for_status()
592→        .map_err(|e| format!("Anthropic request failed: {}", e))?;
593→
594→    let body: AnthropicResponse = response
595→        .json()
596→        .map_err(|e| format!("Failed to decode Anthropic response: {}", e))?;
597→
598→    let text = body
599→        .content
600→        .into_iter()
601→        .filter(|block| block.kind == "text")
602→        .filter_map(|block| block.text)
603→        .collect::<Vec<_>>()
604→        .join("\n");
605→
606→    if text.trim().is_empty() {
607→        return Err("Anthropic response did not include any text output".to_string());
608→    }
609→
610→    Ok(text)
611→}
