621→fn get_checkpoint_diff(
622→    repo_path: String,
623→    commit_sha: String,
624→) -> Result<Vec<FileDiff>, String> {
625→    if commit_sha.is_empty() {
626→        return Err("No commit SHA available for this checkpoint".to_string());
627→    }
628→
629→    let repo = git::open_repo(&repo_path)?;
