633→#[tauri::command]
634→fn run_checkpoint_semantic_review(
635→    repo_path: String,
636→    checkpoint_id: String,
637→    commit_sha: String,
638→) -> Result<semantic_review::RunCheckpointSemanticReviewResponse, String> {
639→    if checkpoint_id.len() < 2 {
640→        return Err("Invalid checkpoint ID".to_string());
641→    }
642→    if commit_sha.is_empty() {
643→        return Err("No commit SHA available for this checkpoint".to_string());
644→    }
645→
646→    let repo = git::open_repo(&repo_path)?;
647→    let files = collect_checkpoint_diff(&repo, &commit_sha)?;
648→    if files.is_empty() {
649→        return Ok(semantic_review::RunCheckpointSemanticReviewResponse {
650→            review_run_id: generate_review_run_id(),
651→            annotations: Vec::new(),
652→        });
653→    }
654→
655→    let transcripts = load_sanitized_checkpoint_transcripts(&repo, &checkpoint_id)?;
656→    let prompt = semantic_review::build_prompt(&files, &transcripts);
657→    let raw_text = call_anthropic_semantic_review(&prompt)?;
658→    let parsed = semantic_review::parse_response_text(&raw_text)?;
659→    let annotations = semantic_review::resolve_annotations(&files, parsed);
660→
661→    Ok(semantic_review::RunCheckpointSemanticReviewResponse {
662→        review_run_id: generate_review_run_id(),
663→        annotations,
664→    })
665→}
