269→/// Count checkpoints per branch by walking the checkpoint tree
270→fn count_checkpoints_per_branch(repo: &Repository) -> std::collections::HashMap<String, u32> {
271→    let mut counts = std::collections::HashMap::new();
272→
273→    let branch_ref = match repo.find_branch("entire/checkpoints/v1", git2::BranchType::Local) {
274→        Ok(b) => b,
275→        Err(_) => return counts,
276→    };
277→
278→    let commit = match branch_ref.get().peel_to_commit() {
279→        Ok(c) => c,
280→        Err(_) => return counts,
281→    };
282→
283→    let tree = match commit.tree() {
284→        Ok(t) => t,
285→        Err(_) => return counts,
286→    };
287→
288→    let _ = tree.walk(git2::TreeWalkMode::PreOrder, |dir, entry| {
289→        let name = match entry.name() {
290→            Some(n) => n,
291→            None => return git2::TreeWalkResult::Ok,
292→        };
293→
294→        if name == "metadata.json" && !dir.is_empty() {
295→            let parts: Vec<&str> = dir.trim_end_matches('/').split('/').collect();
296→            if parts.len() == 2 {
297→                if let Ok(blob) = repo.find_blob(entry.id()) {
298→                    if let Ok(content) = std::str::from_utf8(blob.content()) {
299→                        // Quick parse just the branch field
300→                        if let Ok(val) = serde_json::from_str::<serde_json::Value>(content) {
301→                            if let Some(branch) = val.get("branch").and_then(|b| b.as_str()) {
302→                                *counts.entry(branch.to_string()).or_insert(0) += 1;
303→                            }
304→                        }
305→                    }
306→                }
307→            }
308→        }
309→
310→        git2::TreeWalkResult::Ok
311→    });
312→
313→    counts
314→}
