use crate::checkpoint;
use crate::config;
use crate::git;
use crate::journal;
use crate::journal::github;
use crate::{AnthropicMessage, AnthropicRequest, AnthropicResponse};

/// Gather checkpoint data for a specific date from a repo.
fn gather_day_data(
    repo_path: &str,
    date: &str,
) -> Result<DayData, String> {
    let repo = git::open_repo(repo_path)?;

    // List all checkpoints (no branch filter — we want cross-branch)
    let all_checkpoints = checkpoint::list_checkpoints(&repo, "")?;

    // Filter to checkpoints created on the target date
    let day_checkpoints: Vec<_> = all_checkpoints
        .into_iter()
        .filter(|cp| cp.created_at.starts_with(date))
        .collect();

    let mut total_sessions: u64 = 0;
    let mut total_tokens: u64 = 0;
    let mut total_agent_pct_sum: f64 = 0.0;
    let mut total_agent_pct_count: u64 = 0;

    let mut summaries = Vec::new();

    for cp in &day_checkpoints {
        total_sessions += cp.sessions.len() as u64;
        if let Some(ref tu) = cp.token_usage {
            total_tokens += tu.input_tokens + tu.output_tokens;
        }

        for session in &cp.sessions {
            if let Some(ref attr) = session.initial_attribution {
                total_agent_pct_sum += attr.agent_percentage;
                total_agent_pct_count += 1;
            }

            let intent = session.summary.as_ref()
                .map(|s| s.intent.clone())
                .unwrap_or_default();
            let outcome = session.summary.as_ref()
                .map(|s| s.outcome.clone())
                .unwrap_or_default();

            summaries.push(format!(
                "- [{}] {}: {} → {}",
                cp.branch,
                cp.commit_message,
                intent,
                outcome
            ));
        }
    }

    let avg_ai_pct = if total_agent_pct_count > 0 {
        (total_agent_pct_sum / total_agent_pct_count as f64).round() as u64
    } else {
        0
    };

    // Gather files touched
    let files_touched: Vec<String> = day_checkpoints
        .iter()
        .flat_map(|cp| cp.files_touched.iter().cloned())
        .collect::<std::collections::HashSet<_>>()
        .into_iter()
        .collect();

    let lines_changed = files_touched.len() as u64 * 30; // rough estimate

    Ok(DayData {
        summaries,
        files_touched,
        total_sessions,
        total_tokens,
        avg_ai_pct,
        lines_changed,
    })
}

struct DayData {
    summaries: Vec<String>,
    files_touched: Vec<String>,
    total_sessions: u64,
    total_tokens: u64,
    avg_ai_pct: u64,
    lines_changed: u64,
}

/// Build the Claude prompt for summary generation.
fn build_prompt(
    date: &str,
    repo_name: &str,
    day_data: &DayData,
    prs: &[journal::JournalPR],
    extra_items: &[String],
) -> String {
    let mut prompt = format!(
        "Generate a daily work journal entry for {} in the repository \"{}\".\n\n",
        date, repo_name
    );

    prompt.push_str("## Session Activity\n");
    if day_data.summaries.is_empty() {
        prompt.push_str("No code sessions recorded for this day.\n");
    } else {
        for s in &day_data.summaries {
            prompt.push_str(&format!("{}\n", s));
        }
    }

    if !day_data.files_touched.is_empty() {
        prompt.push_str("\n## Files Touched\n");
        for f in &day_data.files_touched {
            prompt.push_str(&format!("- {}\n", f));
        }
    }

    if !prs.is_empty() {
        prompt.push_str("\n## Pull Requests\n");
        for pr in prs {
            prompt.push_str(&format!(
                "- #{} \"{}\" ({})\n",
                pr.number, pr.title, pr.status
            ));
        }
    }

    if !extra_items.is_empty() {
        prompt.push_str("\n## Non-Code Work (provided by user)\n");
        for item in extra_items {
            prompt.push_str(&format!("- {}\n", item));
        }
    }

    prompt.push_str("\n## Instructions\n");
    prompt.push_str("Respond with ONLY a JSON object (no markdown fences) in this exact format:\n");
    prompt.push_str(r#"{
  "repos": [
    {
      "name": "repo-name",
      "accomplishments": ["concise action-oriented bullet point", ...]
    }
  ],
  "other_work": ["non-code item", ...]
}
"#);
    prompt.push_str("\nRules:\n");
    prompt.push_str("- Group accomplishments by repository name\n");
    prompt.push_str("- Write concise, action-oriented bullet points suitable for standup reporting\n");
    prompt.push_str("- Summarize accomplishments, don't just repeat commit messages\n");
    prompt.push_str("- Include the user's non-code work items in other_work exactly as provided\n");
    prompt.push_str("- If there are no sessions or PRs, still return the structure with empty arrays\n");

    prompt
}

#[derive(serde::Deserialize)]
struct AiResponse {
    repos: Vec<AiRepoSection>,
    #[serde(default)]
    other_work: Vec<String>,
}

#[derive(serde::Deserialize)]
struct AiRepoSection {
    name: String,
    accomplishments: Vec<String>,
}

/// Generate a journal entry for a given date.
pub fn generate_entry(
    repo_path: &str,
    date: &str,
    extra_items: Option<Vec<String>>,
) -> Result<journal::JournalEntry, String> {
    let extra = extra_items.unwrap_or_default();

    // Gather checkpoint data
    let day_data = gather_day_data(repo_path, date)?;

    // Fetch PR data from GitHub
    let prs = github::fetch_prs_for_date(repo_path, date);

    // Get repo name
    let repo_name = std::path::Path::new(repo_path)
        .file_name()
        .map(|n| n.to_string_lossy().to_string())
        .unwrap_or_else(|| "unknown".to_string());

    // Build prompt and call Claude
    let prompt = build_prompt(date, &repo_name, &day_data, &prs, &extra);

    let api_key = config::read_app_settings()
        .anthropic_api_key
        .filter(|k| !k.is_empty())
        .or_else(|| std::env::var("ANTHROPIC_API_KEY").ok())
        .ok_or_else(|| {
            "Anthropic API key is not configured. Set it in Settings or as ANTHROPIC_API_KEY env var."
                .to_string()
        })?;

    let model = std::env::var("ANTHROPIC_MODEL")
        .unwrap_or_else(|_| "claude-sonnet-4-20250514".to_string());

    let client = reqwest::blocking::Client::builder()
        .timeout(std::time::Duration::from_secs(90))
        .build()
        .map_err(|e| format!("Failed to build HTTP client: {}", e))?;

    let response = client
        .post("https://api.anthropic.com/v1/messages")
        .header("x-api-key", &api_key)
        .header("anthropic-version", "2023-06-01")
        .header("content-type", "application/json")
        .json(&AnthropicRequest {
            model,
            max_tokens: 2_000,
            temperature: 0.3,
            system: "You are a work journal assistant. Generate concise daily summaries of development work. Respond with JSON only.".to_string(),
            messages: vec![AnthropicMessage {
                role: "user".to_string(),
                content: prompt,
            }],
        })
        .send()
        .map_err(|e| format!("Anthropic request failed: {}", e))?
        .error_for_status()
        .map_err(|e| format!("Anthropic request failed: {}", e))?;

    let body: AnthropicResponse = response
        .json()
        .map_err(|e| format!("Failed to decode Anthropic response: {}", e))?;

    let text = body
        .content
        .into_iter()
        .filter(|block| block.kind == "text")
        .filter_map(|block| block.text)
        .collect::<Vec<_>>()
        .join("\n");

    // Strip markdown code fences if present
    let json_text = text
        .trim()
        .trim_start_matches("```json")
        .trim_start_matches("```")
        .trim_end_matches("```")
        .trim();

    let ai_response: AiResponse = serde_json::from_str(json_text)
        .map_err(|e| format!("Failed to parse AI response: {} — raw: {}", e, json_text))?;

    // Build the full entry
    let generated_at = {
        let now = std::time::SystemTime::now()
            .duration_since(std::time::UNIX_EPOCH)
            .unwrap_or_default()
            .as_secs();
        format!("{}T00:00:00Z", journal::format_unix_date(now as i64))
    };

    // Map AI repo sections with PR data
    let repos: Vec<journal::RepoSection> = ai_response
        .repos
        .into_iter()
        .map(|ai_repo| {
            // Find PRs that match this repo (for single-repo, all PRs go here)
            let repo_prs = prs.clone();
            let lines_added = day_data.lines_changed / 2;
            let lines_removed = day_data.lines_changed / 4;

            journal::RepoSection {
                name: ai_repo.name,
                lines_added,
                lines_removed,
                accomplishments: ai_repo.accomplishments,
                pull_requests: repo_prs,
            }
        })
        .collect();

    let total_prs = repos.iter().map(|r| r.pull_requests.len() as u64).sum();

    let entry = journal::JournalEntry {
        date: date.to_string(),
        generated_at,
        repos,
        other_work: ai_response.other_work,
        stats: journal::JournalStats {
            lines_changed: day_data.lines_changed,
            sessions: day_data.total_sessions,
            prs: total_prs,
            ai_authored_pct: day_data.avg_ai_pct,
            tokens: day_data.total_tokens,
        },
    };

    // Save to disk
    journal::save_entry(repo_path, &entry)?;

    Ok(entry)
}
