}

export function DateJumper({ dates, onDateClick }: DateJumperProps) {
  const today = new Date().toISOString().slice(0, 10);

  // Group dates by month
  let currentMonth = "";

  return (
    <div className="flex w-12 flex-col items-center gap-0.5 overflow-y-auto border-l border-border bg-bg-raised py-3">
      {dates.map((d) => {
        const month = d.date.slice(0, 7); // YYYY-MM
        const day = parseInt(d.date.slice(8, 10), 10);
        const monthLabel = month !== currentMonth;
        if (monthLabel) currentMonth = month;

        const isToday = d.date === today;
        const intensityBg =
          d.activity_level === 0
            ? ""
            : d.activity_level === 1
              ? "bg-accent/10"
              : d.activity_level === 2
                ? "bg-accent/20"
                : d.activity_level === 3
                  ? "bg-accent/30"
                  : "bg-accent/40";

        return (
          <div key={d.date}>
            {monthLabel && (
              <div className="mb-1 mt-1 text-center text-[9px] font-semibold uppercase text-fg-subtle">
                {new Date(d.date + "T12:00:00").toLocaleString("en-US", { month: "short" })}
              </div>
            )}
            <button
              onClick={() => onDateClick(d.date)}
              className={`flex h-[22px] w-7 items-center justify-center rounded text-[10px] ${
                isToday
                  ? "bg-accent font-semibold text-white"
                  : d.has_entry
                    ? `cursor-pointer font-medium text-fg ${intensityBg} hover:bg-accent/25`
                    : "cursor-pointer text-fg-subtle hover:bg-bg-hover"
              }`}
            >
              {day}
            </button>
          </div>
        );
      })}
    </div>
  );
}
```

