109→/// Get the journal directory for a repo, creating it if needed.
110→pub fn journal_dir(repo_path: &str) -> PathBuf {
111→    let dir = Path::new(repo_path).join(".entire/journal");
112→    let _ = fs::create_dir_all(&dir);
113→    dir
114→}
115→
116→/// List journal entries from markdown files, sorted newest first.
117→/// `limit` defaults to 100.
118→pub fn list_entries(repo_path: &str, limit: usize) -> Result<Vec<JournalEntry>, String> {
119→    let dir = journal_dir(repo_path);
120→    if !dir.exists() {
121→        return Ok(Vec::new());
122→    }
123→
124→    let mut files: Vec<_> = fs::read_dir(&dir)
125→        .map_err(|e| format!("Failed to read journal dir: {}", e))?
126→        .filter_map(|e| e.ok())
127→        .filter(|e| {
128→            e.path()
129→                .extension()
130→                .map_or(false, |ext| ext == "md")
131→        })
132→        .collect();
133→
134→    // Sort by filename descending (YYYY-MM-DD.md sorts chronologically)
135→    files.sort_by(|a, b| b.file_name().cmp(&a.file_name()));
136→    files.truncate(limit);
137→
138→    let mut entries = Vec::new();
139→    for file in files {
140→        let content = fs::read_to_string(file.path())
141→            .map_err(|e| format!("Failed to read {}: {}", file.path().display(), e))?;
142→        match parse_markdown(&content) {
143→            Ok(entry) => entries.push(entry),
144→            Err(e) => eprintln!("Skipping {}: {}", file.path().display(), e),
145→        }
146→    }
147→
148→    Ok(entries)
149→}
