151→/// Get a single journal entry by date (YYYY-MM-DD).
152→pub fn get_entry(repo_path: &str, date: &str) -> Result<JournalEntry, String> {
153→    let path = journal_dir(repo_path).join(format!("{}.md", date));
154→    if !path.exists() {
155→        return Err(format!("No journal entry for {}", date));
156→    }
157→    let content = fs::read_to_string(&path)
158→        .map_err(|e| format!("Failed to read entry: {}", e))?;
159→    parse_markdown(&content)
160→}
