162→/// Get date info for the date jumper rail.
163→pub fn list_dates(repo_path: &str, limit: usize) -> Result<Vec<JournalDateInfo>, String> {
164→    let dir = journal_dir(repo_path);
165→
166→    // Build a set of dates that have entries
167→    let mut entry_dates = std::collections::HashSet::new();
168→    let mut stats_map = std::collections::HashMap::new();
169→
170→    if dir.exists() {
171→        if let Ok(read_dir) = fs::read_dir(&dir) {
172→            for entry in read_dir.filter_map(|e| e.ok()) {
173→                let path = entry.path();
174→                if path.extension().map_or(false, |ext| ext == "md") {
175→                    if let Some(stem) = path.file_stem().and_then(|s| s.to_str()) {
176→                        entry_dates.insert(stem.to_string());
177→                        // Quick parse frontmatter for stats
178→                        if let Ok(content) = fs::read_to_string(&path) {
179→                            if let Ok(parsed) = parse_frontmatter_only(&content) {
180→                                stats_map.insert(stem.to_string(), parsed);
181→                            }
182→                        }
183→                    }
184→                }
185→            }
186→        }
187→    }
188→
189→    // Generate last `limit` days
190→    let today = current_date();
191→    let mut dates = Vec::new();
192→    for i in 0..limit {
193→        let date = subtract_days(&today, i as i64);
194→        let has_entry = entry_dates.contains(&date);
195→        let activity_level = stats_map
196→            .get(&date)
197→            .map(|s| {
198→                // Scale lines_changed to 0-4
199→                match s.lines_changed {
200→                    0 => 0,

200→                    0 => 0,
201→                    1..=100 => 1,
202→                    101..=500 => 2,
203→                    501..=1000 => 3,
204→                    _ => 4,
205→                }
206→            })
207→            .unwrap_or(0);
208→
209→        dates.push(JournalDateInfo {
210→            date,
211→            has_entry,
212→            activity_level,
213→        });
214→    }
215→
216→    Ok(dates)
217→}
