219→/// Save a journal entry as a markdown file.
220→pub fn save_entry(repo_path: &str, entry: &JournalEntry) -> Result<(), String> {
221→    let dir = journal_dir(repo_path);
222→    let path = dir.join(format!("{}.md", entry.date));
223→    let content = render_markdown(entry);
224→    fs::write(&path, content)
225→        .map_err(|e| format!("Failed to write journal entry: {}", e))
226→}
227→
228→/// Parse a journal markdown file into a JournalEntry.
229→pub fn parse_markdown(content: &str) -> Result<JournalEntry, String> {
230→    // Split frontmatter from body
231→    let (frontmatter, body) = split_frontmatter(content)?;
232→
233→    // Parse YAML frontmatter
234→    let date = extract_yaml_field(&frontmatter, "date")
235→        .ok_or("Missing date in frontmatter")?;
236→    let generated_at = extract_yaml_field(&frontmatter, "generated_at")
237→        .unwrap_or_default();
238→    let stats = parse_frontmatter_only(content)?;
239→
240→    // Parse body into repo sections and other work
241→    let (repos, other_work) = parse_body(&body);
242→
243→    Ok(JournalEntry {
244→        date,
245→        generated_at,
246→        repos,
247→        other_work,
248→        stats,
249→    })
250→}
251→
252→fn split_frontmatter(content: &str) -> Result<(String, String), String> {
253→    let content = content.trim();
254→    if !content.starts_with("---") {
255→        return Err("No frontmatter found".to_string());
256→    }
257→    let rest = &content[3..];
258→    let end = rest.find("---").ok_or("Unterminated frontmatter")?;
259→    let frontmatter = rest[..end].trim().to_string();
260→    let body = rest[end + 3..].trim().to_string();
261→    Ok((frontmatter, body))
262→}
263→
264→fn extract_yaml_field(yaml: &str, field: &str) -> Option<String> {
265→    for line in yaml.lines() {
266→        let line = line.trim();
267→        if let Some(rest) = line.strip_prefix(&format!("{}:", field)) {
268→            let value = rest.trim().trim_matches('"').trim_matches('\'');
269→            if !value.is_empty() {
270→                return Some(value.to_string());
271→            }
272→        }
273→    }
274→    None
275→}
276→
277→fn parse_frontmatter_only(content: &str) -> Result<JournalStats, String> {
278→    let (frontmatter, _) = split_frontmatter(content)?;
279→
280→    let lines_changed = extract_yaml_field(&frontmatter, "lines_changed")
281→        .and_then(|v| v.parse().ok())
282→        .unwrap_or(0);
283→    let sessions = extract_yaml_field(&frontmatter, "sessions")
284→        .and_then(|v| v.parse().ok())
285→        .unwrap_or(0);
286→    let prs = extract_yaml_field(&frontmatter, "prs")
287→        .and_then(|v| v.parse().ok())
288→        .unwrap_or(0);
289→    let ai_authored_pct = extract_yaml_field(&frontmatter, "ai_authored_pct")
290→        .and_then(|v| v.parse().ok())
291→        .unwrap_or(0);
292→    let tokens = extract_yaml_field(&frontmatter, "tokens")
293→        .and_then(|v| v.parse().ok())
294→        .unwrap_or(0);
295→
296→    Ok(JournalStats {
297→        lines_changed,
298→        sessions,
299→        prs,
300→        ai_authored_pct,
301→        tokens,
302→    })
303→}
304→
305→fn parse_body(body: &str) -> (Vec<RepoSection>, Vec<String>) {
306→    let mut repos = Vec::new();
307→    let mut other_work = Vec::new();
308→    let mut current_repo: Option<RepoSection> = None;
309→    let mut in_prs = false;
310→    let mut in_other_work = false;
311→
312→    for line in body.lines() {
313→        let trimmed = line.trim();
314→
315→        // H2 heading = repo name or "Other Work"
316→        if let Some(heading) = trimmed.strip_prefix("## ") {
317→            // Save previous repo
318→            if let Some(repo) = current_repo.take() {
319→                repos.push(repo);
320→            }
321→            in_prs = false;
322→
323→            if heading == "Other Work" {
324→                in_other_work = true;
325→                continue;
326→            }
327→
328→            in_other_work = false;
329→            current_repo = Some(RepoSection {
330→                name: heading.to_string(),
331→                lines_added: 0,
332→                lines_removed: 0,
333→                accomplishments: Vec::new(),
334→                pull_requests: Vec::new(),
335→            });
336→            continue;
337→        }
338→
339→        // H3 heading = "Pull Requests" subsection
340→        if trimmed.starts_with("### Pull Requests") {
341→            in_prs = true;
342→            continue;
343→        }
344→
345→        // Lines diff stats: _+716 -131_
346→        if trimmed.starts_with("_+") && trimmed.ends_with('_') {
347→            if let Some(ref mut repo) = current_repo {
348→                let inner = &trimmed[1..trimmed.len() - 1];
349→                let parts: Vec<&str> = inner.split_whitespace().collect();
350→                if parts.len() == 2 {
351→                    repo.lines_added = parts[0].trim_start_matches('+').parse().unwrap_or(0);
352→                    repo.lines_removed = parts[1].trim_start_matches('-').parse().unwrap_or(0);
353→                }
354→            }
355→            continue;
356→        }
357→
358→        // Bullet points
359→        if let Some(bullet_content) = trimmed.strip_prefix("- ") {
360→            if in_other_work {
361→                other_work.push(bullet_content.to_string());
362→            } else if in_prs {
363→                if let Some(ref mut repo) = current_repo {
364→                    if let Some(pr) = parse_pr_line(bullet_content) {
365→                        repo.pull_requests.push(pr);
366→                    }
367→                }
368→            } else if let Some(ref mut repo) = current_repo {
369→                repo.accomplishments.push(bullet_content.to_string());
370→            }
371→        }
372→    }
373→
374→    // Don't forget last repo
375→    if let Some(repo) = current_repo {
376→        repos.push(repo);
377→    }
378→
379→    (repos, other_work)
380→}
