382→/// Parse a PR line like: **Settings page rebuild** #142 — merged
383→fn parse_pr_line(line: &str) -> Option<JournalPR> {
384→    // Pattern: **title** #number — status
385→    let bold_start = line.find("**")?;
386→    let bold_end = line[bold_start + 2..].find("**")? + bold_start + 2;
387→    let title = line[bold_start + 2..bold_end].to_string();
388→
389→    let rest = &line[bold_end + 2..];
390→    let hash_pos = rest.find('#')?;
391→    let after_hash = &rest[hash_pos + 1..];
392→
393→    // Find the number (digits until non-digit)
394→    let num_end = after_hash.find(|c: char| !c.is_ascii_digit()).unwrap_or(after_hash.len());
395→    let number: u64 = after_hash[..num_end].parse().ok()?;
396→
397→    // Find status after — or -
398→    let status = if let Some(dash_pos) = rest.find('—').or_else(|| rest.find(" - ")) {
399→        let s = rest[dash_pos..].trim_start_matches('—').trim_start_matches(" - ").trim();

400→        s.to_string()
401→    } else {
402→        "open".to_string()
403→    };
404→
405→    Some(JournalPR {
406→        title,
407→        number,
408→        status,
409→        additions: 0,
410→        deletions: 0,
411→        url: String::new(),
412→    })
413→}
