415→/// Render a JournalEntry as a markdown string.
416→pub fn render_markdown(entry: &JournalEntry) -> String {
417→    let mut out = String::new();
418→
419→    // Frontmatter
420→    out.push_str("---\n");
421→    out.push_str(&format!("date: {}\n", entry.date));
422→    out.push_str(&format!("generated_at: {}\n", entry.generated_at));
423→
424→    // Repos list
425→    out.push_str("repos:\n");
426→    for repo in &entry.repos {
427→        out.push_str(&format!("  - {}\n", repo.name));
428→    }
429→
430→    // Stats
431→    out.push_str("stats:\n");
432→    out.push_str(&format!("  lines_changed: {}\n", entry.stats.lines_changed));
433→    out.push_str(&format!("  sessions: {}\n", entry.stats.sessions));
434→    out.push_str(&format!("  prs: {}\n", entry.stats.prs));
435→    out.push_str(&format!("  ai_authored_pct: {}\n", entry.stats.ai_authored_pct));
436→    out.push_str(&format!("  tokens: {}\n", entry.stats.tokens));
437→    out.push_str("---\n\n");
438→
439→    // Repo sections
440→    for repo in &entry.repos {
441→        out.push_str(&format!("## {}\n", repo.name));
442→        out.push_str(&format!("_+{} -{}_ \n\n", repo.lines_added, repo.lines_removed));
443→
444→        for item in &repo.accomplishments {
445→            out.push_str(&format!("- {}\n", item));
446→        }
447→
448→        if !repo.pull_requests.is_empty() {
449→            out.push_str("\n### Pull Requests\n");
450→            for pr in &repo.pull_requests {
451→                out.push_str(&format!("- **{}** #{} — {}\n", pr.title, pr.number, pr.status));
452→            }
453→        }
454→
455→        out.push('\n');
456→    }
457→
458→    // Other work
459→    if !entry.other_work.is_empty() {
460→        out.push_str("## Other Work\n");
461→        for item in &entry.other_work {
462→            out.push_str(&format!("- {}\n", item));
463→        }
464→    }
465→
466→    out
467→}
