469→fn current_date() -> String {
470→    let now = std::time::SystemTime::now()
471→        .duration_since(std::time::UNIX_EPOCH)
472→        .unwrap_or_default()
473→        .as_secs();
474→    format_unix_date(now as i64)
475→}
476→
477→fn format_unix_date(secs: i64) -> String {
478→    // Simple date formatting from unix timestamp
479→    let days = secs / 86400;
480→    let (year, month, day) = days_to_ymd(days);
481→    format!("{:04}-{:02}-{:02}", year, month, day)
482→}
483→
484→fn subtract_days(date: &str, n: i64) -> String {
485→    // Parse YYYY-MM-DD, subtract n days, return YYYY-MM-DD
486→    let parts: Vec<i64> = date.split('-').filter_map(|p| p.parse().ok()).collect();
487→    if parts.len() != 3 {
488→        return date.to_string();
489→    }
490→    let total_days = ymd_to_days(parts[0], parts[1], parts[2]) - n;
491→    let (y, m, d) = days_to_ymd(total_days);
492→    format!("{:04}-{:02}-{:02}", y, m, d)
493→}
494→
495→fn ymd_to_days(year: i64, month: i64, day: i64) -> i64 {
496→    let mut days: i64 = 0;
497→    for y in 1970..year {
498→        days += if is_leap(y) { 366 } else { 365 };
499→    }
500→    let month_lengths = [0, 31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];
501→    for m in 1..month {
502→        days += month_lengths[m as usize];
503→        if m == 2 && is_leap(year) {
504→            days += 1;
505→        }
506→    }
507→    days + day - 1
508→}
509→
510→fn days_to_ymd(mut days: i64) -> (i64, i64, i64) {
511→    let mut year = 1970;
512→    loop {
513→        let year_days = if is_leap(year) { 366 } else { 365 };
514→        if days < year_days {
515→            break;
516→        }
517→        days -= year_days;
518→        year += 1;
519→    }
520→    let month_lengths = if is_leap(year) {
521→        [31, 29, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31]
522→    } else {
523→        [31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31]
524→    };
525→    let mut month = 1;
526→    for &ml in &month_lengths {
527→        if days < ml {
528→            break;
529→        }
530→        days -= ml;
531→        month += 1;
532→    }
533→    (year, month, days + 1)
534→}
535→
536→fn is_leap(y: i64) -> bool {
537→    y % 4 == 0 && (y % 100 != 0 || y % 400 == 0)
538→}
