643→/// Parse a GitHub owner/repo from a git remote URL.
644→/// Handles: https://github.com/owner/repo.git, git@github.com:owner/repo.git
645→pub fn parse_github_remote(remote_url: &str) -> Option<(String, String)> {
646→    let url = remote_url.trim().trim_end_matches(".git");
647→
648→    // SSH: git@github.com:owner/repo
649→    if let Some(rest) = url.strip_prefix("git@github.com:") {
650→        let parts: Vec<&str> = rest.splitn(2, '/').collect();
651→        if parts.len() == 2 {
652→            return Some((parts[0].to_string(), parts[1].to_string()));
653→        }
654→    }
655→
656→    // HTTPS: https://github.com/owner/repo
657→    if url.contains("github.com/") {
658→        let after = url.split("github.com/").nth(1)?;
659→        let parts: Vec<&str> = after.splitn(2, '/').collect();
660→        if parts.len() == 2 {
661→            return Some((parts[0].to_string(), parts[1].to_string()));
662→        }
663→    }
664→
665→    None
666→}
