672→        .current_dir(repo_path)
673→        .output()
674→        .ok()?;
675→
676→    if output.status.success() {
677→        Some(String::from_utf8_lossy(&output.stdout).trim().to_string())
678→    } else {
679→        None
680→    }
681→}
