726→/// Fetch PRs for a repo that were updated on a given date.
727→/// Returns empty vec if no GitHub token is available (graceful degradation).
728→pub fn fetch_prs_for_date(
729→    repo_path: &str,
730→    date: &str,
731→) -> Vec<JournalPR> {
732→    let remote_url = match get_remote_url(repo_path) {
733→        Some(url) => url,
734→        None => return Vec::new(),
735→    };
736→
737→    let (owner, repo) = match parse_github_remote(&remote_url) {
738→        Some(pair) => pair,
739→        None => return Vec::new(),
740→    };
741→
742→    let token = match get_github_token() {
743→        Some(t) => t,
744→        None => return Vec::new(),
745→    };
746→
747→    let query = format!("repo:{}/{} is:pr updated:{}", owner, repo, date);
748→    let url = format!(
749→        "https://api.github.com/search/issues?q={}&per_page=100",
750→        urlencoded(&query)
751→    );
752→
753→    let client = match reqwest::blocking::Client::builder()
754→        .timeout(std::time::Duration::from_secs(15))
755→        .build()
756→    {
757→        Ok(c) => c,
758→        Err(_) => return Vec::new(),
759→    };
760→
761→    let response = client
762→        .get(&url)
763→        .header("Authorization", format!("Bearer {}", token))
764→        .header("Accept", "application/vnd.github+json")
765→        .header("User-Agent", "entire-desktop")
766→        .header("X-GitHub-Api-Version", "2022-11-28")
767→        .send();
768→
769→    let response = match response {
770→        Ok(r) => r,
771→        Err(e) => {
772→            eprintln!("GitHub API error: {}", e);
773→            return Vec::new();
774→        }
775→    };
776→
777→    if !response.status().is_success() {
778→        eprintln!("GitHub API returned status: {}", response.status());
779→        return Vec::new();
780→    }
781→
782→    let search: SearchResponse = match response.json() {
783→        Ok(s) => s,
784→        Err(e) => {
785→            eprintln!("Failed to parse GitHub response: {}", e);
786→            return Vec::new();
787→        }
788→    };
789→
790→    search
791→        .items
792→        .into_iter()
793→        .map(|item| {
794→            let status = if item.pull_request
795→                .as_ref()
796→                .and_then(|pr| pr.merged_at.as_ref())
797→                .is_some()
798→            {
799→                "merged".to_string()

800→            } else if item.state == "closed" {
801→                "closed".to_string()
802→            } else {
803→                "open".to_string()
804→            };
805→
806→            JournalPR {
807→                title: item.title,
808→                number: item.number,
809→                status,
810→                additions: 0,
811→                deletions: 0,
812→                url: item.html_url,
813→            }
814→        })
815→        .collect()
816→}
817→
818→fn urlencoded(s: &str) -> String {
819→    s.replace(' ', "+")
820→        .replace(':', "%3A")
821→        .replace('/', "%2F")
822→}
