888→/// Gather checkpoint data for a specific date from a repo.
889→fn gather_day_data(
890→    repo_path: &str,
891→    date: &str,
892→) -> Result<DayData, String> {
893→    let repo = git::open_repo(repo_path)?;
894→
895→    // List all checkpoints (no branch filter — we want cross-branch)
896→    let all_checkpoints = checkpoint::list_checkpoints(&repo, "")?;
897→
898→    // Filter to checkpoints created on the target date
899→    let day_checkpoints: Vec<_> = all_checkpoints
900→        .into_iter()
901→        .filter(|cp| cp.created_at.starts_with(date))
902→        .collect();
903→
904→    let mut total_sessions: u64 = 0;
905→    let mut total_tokens: u64 = 0;
906→    let mut total_agent_pct_sum: f64 = 0.0;
907→    let mut total_agent_pct_count: u64 = 0;
908→
909→    let mut summaries = Vec::new();
910→
911→    for cp in &day_checkpoints {
912→        total_sessions += cp.sessions.len() as u64;
913→        if let Some(ref tu) = cp.token_usage {
914→            total_tokens += tu.input_tokens + tu.output_tokens;
915→        }
916→
917→        for session in &cp.sessions {
918→            if let Some(ref attr) = session.initial_attribution {
919→                total_agent_pct_sum += attr.agent_percentage;
920→                total_agent_pct_count += 1;
921→            }
922→
923→            let intent = session.summary.as_ref()
924→                .map(|s| s.intent.clone())
925→                .unwrap_or_default();
926→            let outcome = session.summary.as_ref()
927→                .map(|s| s.outcome.clone())
928→                .unwrap_or_default();
929→
930→            summaries.push(format!(
931→                "- [{}] {}: {} → {}",
932→                cp.branch,
933→                cp.commit_message,
934→                intent,
935→                outcome
936→            ));
937→        }
938→    }
939→
940→    let avg_ai_pct = if total_agent_pct_count > 0 {
941→        (total_agent_pct_sum / total_agent_pct_count as f64).round() as u64
942→    } else {
943→        0
944→    };
945→
946→    // Gather files touched
947→    let files_touched: Vec<String> = day_checkpoints
948→        .iter()
949→        .flat_map(|cp| cp.files_touched.iter().cloned())
950→        .collect::<std::collections::HashSet<_>>()
951→        .into_iter()
952→        .collect();
953→
954→    let lines_changed = files_touched.len() as u64 * 30; // rough estimate
955→
956→    Ok(DayData {
957→        summaries,
958→        files_touched,
