975→/// Build the Claude prompt for summary generation.
976→fn build_prompt(
977→    date: &str,
978→    repo_name: &str,
979→    day_data: &DayData,
980→    prs: &[journal::JournalPR],
981→    extra_items: &[String],
982→) -> String {
983→    let mut prompt = format!(
984→        "Generate a daily work journal entry for {} in the repository \"{}\".\n\n",
985→        date, repo_name
986→    );
987→
988→    prompt.push_str("## Session Activity\n");
989→    if day_data.summaries.is_empty() {
990→        prompt.push_str("No code sessions recorded for this day.\n");
991→    } else {
992→        for s in &day_data.summaries {
993→            prompt.push_str(&format!("{}\n", s));
994→        }
995→    }
996→
997→    if !day_data.files_touched.is_empty() {
998→        prompt.push_str("\n## Files Touched\n");
999→        for f in &day_data.files_touched {

1000→            prompt.push_str(&format!("- {}\n", f));
1001→        }
1002→    }
1003→
1004→    if !prs.is_empty() {
1005→        prompt.push_str("\n## Pull Requests\n");
1006→        for pr in prs {
1007→            prompt.push_str(&format!(
1008→                "- #{} \"{}\" ({})\n",
1009→                pr.number, pr.title, pr.status
1010→            ));
1011→        }
1012→    }
1013→
1014→    if !extra_items.is_empty() {
1015→        prompt.push_str("\n## Non-Code Work (provided by user)\n");
1016→        for item in extra_items {
1017→            prompt.push_str(&format!("- {}\n", item));
1018→        }
1019→    }
1020→
1021→    prompt.push_str("\n## Instructions\n");
1022→    prompt.push_str("Respond with ONLY a JSON object (no markdown fences) in this exact format:\n");
1023→    prompt.push_str(r#"{
1024→  "repos": [
1025→    {
1026→      "name": "repo-name",
1027→      "accomplishments": ["concise action-oriented bullet point", ...]
1028→    }
1029→  ],
1030→  "other_work": ["non-code item", ...]
1031→}
1032→"#);
1033→    prompt.push_str("\nRules:\n");
1034→    prompt.push_str("- Group accomplishments by repository name\n");
1035→    prompt.push_str("- Write concise, action-oriented bullet points suitable for standup reporting\n");
1036→    prompt.push_str("- Summarize accomplishments, don't just repeat commit messages\n");
1037→    prompt.push_str("- Include the user's non-code work items in other_work exactly as provided\n");
1038→    prompt.push_str("- If there are no sessions or PRs, still return the structure with empty arrays\n");
1039→
1040→    prompt
1041→}
