1044→struct AiResponse {
1045→    repos: Vec<AiRepoSection>,
1046→    #[serde(default)]
1047→    other_work: Vec<String>,
1048→}
1049→
1050→#[derive(serde::Deserialize)]
1051→struct AiRepoSection {
1052→    name: String,
