1056→/// Generate a journal entry for a given date.
1057→pub fn generate_entry(
1058→    repo_path: &str,
1059→    date: &str,
1060→    extra_items: Option<Vec<String>>,
1061→) -> Result<journal::JournalEntry, String> {
1062→    let extra = extra_items.unwrap_or_default();
1063→
1064→    // Gather checkpoint data
1065→    let day_data = gather_day_data(repo_path, date)?;
1066→
1067→    // Fetch PR data from GitHub
1068→    let prs = github::fetch_prs_for_date(repo_path, date);
1069→
1070→    // Get repo name
1071→    let repo_name = std::path::Path::new(repo_path)
1072→        .file_name()
1073→        .map(|n| n.to_string_lossy().to_string())
1074→        .unwrap_or_else(|| "unknown".to_string());
1075→
1076→    // Build prompt and call Claude
1077→    let prompt = build_prompt(date, &repo_name, &day_data, &prs, &extra);
1078→
1079→    let api_key = config::read_app_settings()
1080→        .anthropic_api_key
1081→        .filter(|k| !k.is_empty())
1082→        .or_else(|| std::env::var("ANTHROPIC_API_KEY").ok())
1083→        .ok_or_else(|| {
1084→            "Anthropic API key is not configured. Set it in Settings or as ANTHROPIC_API_KEY env var."
1085→                .to_string()
1086→        })?;
1087→
1088→    let model = std::env::var("ANTHROPIC_MODEL")
1089→        .unwrap_or_else(|_| "claude-sonnet-4-20250514".to_string());
1090→
1091→    let client = reqwest::blocking::Client::builder()
1092→        .timeout(std::time::Duration::from_secs(90))
1093→        .build()
1094→        .map_err(|e| format!("Failed to build HTTP client: {}", e))?;
1095→
1096→    let response = client
1097→        .post("https://api.anthropic.com/v1/messages")
1098→        .header("x-api-key", &api_key)
1099→        .header("anthropic-version", "2023-06-01")
1100→        .header("content-type", "application/json")
1101→        .json(&AnthropicRequest {
1102→            model,
1103→            max_tokens: 2_000,
1104→            temperature: 0.3,
1105→            system: "You are a work journal assistant. Generate concise daily summaries of development work. Respond with JSON only.".to_string(),
1106→            messages: vec![AnthropicMessage {
1107→                role: "user".to_string(),
1108→                content: prompt,
1109→            }],
1110→        })
1111→        .send()
1112→        .map_err(|e| format!("Anthropic request failed: {}", e))?
1113→        .error_for_status()
1114→        .map_err(|e| format!("Anthropic request failed: {}", e))?;
1115→
1116→    let body: AnthropicResponse = response
1117→        .json()
1118→        .map_err(|e| format!("Failed to decode Anthropic response: {}", e))?;
1119→
1120→    let text = body
1121→        .content
1122→        .into_iter()
1123→        .filter(|block| block.kind == "text")
1124→        .filter_map(|block| block.text)
1125→        .collect::<Vec<_>>()
1126→        .join("\n");
1127→
1128→    // Strip markdown code fences if present
1129→    let json_text = text
1130→        .trim()
1131→        .trim_start_matches("```json")
1132→        .trim_start_matches("```")
1133→        .trim_end_matches("```")
1134→        .trim();
1135→
1136→    let ai_response: AiResponse = serde_json::from_str(json_text)
1137→        .map_err(|e| format!("Failed to parse AI response: {} — raw: {}", e, json_text))?;
1138→
1139→    // Build the full entry
1140→    let generated_at = {
1141→        let now = std::time::SystemTime::now()
1142→            .duration_since(std::time::UNIX_EPOCH)
1143→            .unwrap_or_default()
1144→            .as_secs();
1145→        format!("{}T00:00:00Z", journal::format_unix_date(now as i64))
1146→    };
1147→
1148→    // Map AI repo sections with PR data
1149→    let repos: Vec<journal::RepoSection> = ai_response
1150→        .repos
1151→        .into_iter()
1152→        .map(|ai_repo| {
1153→            // Find PRs that match this repo (for single-repo, all PRs go here)
1154→            let repo_prs = prs.clone();
1155→            let lines_added = day_data.lines_changed / 2;
1156→            let lines_removed = day_data.lines_changed / 4;
1157→
1158→            journal::RepoSection {
1159→                name: ai_repo.name,
1160→                lines_added,
1161→                lines_removed,
1162→                accomplishments: ai_repo.accomplishments,
1163→                pull_requests: repo_prs,
1164→            }
1165→        })
1166→        .collect();
1167→
1168→    let total_prs = repos.iter().map(|r| r.pull_requests.len() as u64).sum();
1169→
1170→    let entry = journal::JournalEntry {
1171→        date: date.to_string(),
1172→        generated_at,
1173→        repos,
1174→        other_work: ai_response.other_work,
1175→        stats: journal::JournalStats {
1176→            lines_changed: day_data.lines_changed,
1177→            sessions: day_data.total_sessions,
1178→            prs: total_prs,
1179→            ai_authored_pct: day_data.avg_ai_pct,
1180→            tokens: day_data.total_tokens,
1181→        },
1182→    };
1183→
1184→    // Save to disk
1185→    journal::save_entry(repo_path, &entry)?;
1186→
1187→    Ok(entry)
1188→}
1189→```
